#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int cnt0 = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x==0) cnt0++;
        }
        int ans = cnt0 > (N - cnt0) ? cnt0 : (N - cnt0);
        printf("%d\n", ans);
    }
    return 0;
}

