import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cnt0 = 0
        for _ in range(N):
            if int(next(it)) == 0:
                cnt0 += 1
        ans = cnt0 if cnt0 > N - cnt0 else N - cnt0
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

